#[async_trait]
impl<R: ThumbnailProjectionRepository> ThumbnailEventHandler for ThumbnailProjector<R> {

    async fn on_created(&self, event: ThumbnailCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = ThumbnailProjection::new(
            event.id,
            event.file_id,
            event.size,
            event.width,
            event.height,
            event.storage_key,
            event.storage_backend,
            event.mime_type,
            event.format,
            event.quality,
            event.size_bytes,
            event.generated_at,
            event.generation_time_ms,
            event.source_version,
            event.cdn_url,
            event.cache_expires_at,
            event.is_stale,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: ThumbnailUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.file_id = event.file_id;
            projection.size = event.size;
            projection.width = event.width;
            projection.height = event.height;
            projection.storage_key = event.storage_key;
            projection.storage_backend = event.storage_backend;
            projection.mime_type = event.mime_type;
            projection.format = event.format;
            projection.quality = event.quality;
            projection.size_bytes = event.size_bytes;
            projection.generated_at = event.generated_at;
            projection.generation_time_ms = event.generation_time_ms;
            projection.source_version = event.source_version;
            projection.cdn_url = event.cdn_url;
            projection.cache_expires_at = event.cache_expires_at;
            projection.is_stale = event.is_stale;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: ThumbnailDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

